const content = `# Notification Prototype — Dinadan (Jester Knight)

## Concept

A minimal standalone TypeScript snippet demonstrating a notification callback system for swarm pipeline completion. Two channels: **file** (writes to a local markdown file) and **webhook** (POSTs JSON to an HTTP endpoint).

This is a **proof of concept** — not integrated into the pipeline. It validates the channel interface and dispatch patterns before production wiring.

---

## Code

\`\`\`typescript
/**
 * Standalone notification prototype.
 * Run: \`bun run dinadan-notify.ts\`
 * Tests file + webhook channels without any external dependencies.
 */

// ============================================================================
// Types
// ============================================================================

/** Result of a swarm pipeline run — what gets sent to every channel. */
interface NotificationPayload {
  /** Pipeline name from swarm YAML */
  name: string;
  /** Pipeline mode (pipeline | loop) */
  mode: string;
  /** Final status */
  status: "completed" | "failed" | "aborted";
  /** Iterations completed */
  iterations: number;
  /** Per-agent results */
  agents: Record<string, { status: string; duration: string }>;
  /** Non-empty when status !== "completed" */
  errors: string[];
  /** ISO-8601 timestamp */
  timestamp: string;
}

/** Result of a single notification dispatch. */
interface ChannelResult {
  channel: string;
  success: boolean;
  error?: string;
  durationMs: number;
}

/** Contract every notification channel must satisfy. */
interface NotificationChannel {
  readonly name: string;
  send(payload: NotificationPayload): Promise<void>;
}

// ============================================================================
// Channels
// ============================================================================

/** Writes notification payload as formatted markdown to a local file. */
class FileChannel implements NotificationChannel {
  readonly name: string;

  constructor(readonly outputPath: string) {
    this.name = \`file:\${outputPath}\`;
  }

  async send(payload: NotificationPayload): Promise<void> {
    const markdown = buildMarkdown(payload);
    await Bun.write(this.outputPath, markdown);
  }
}

/** POSTs notification payload as JSON to a webhook URL. */
class WebhookChannel implements NotificationChannel {
  readonly name: string;

  constructor(
    readonly url: string,
    readonly options: {
      /** Bearer token or API key for Authorization header */
      secret?: string;
      /** Request timeout in ms (default 10_000) */
      timeout?: number;
    } = {},
  ) {
    this.name = \`webhook:\${url}\`;
  }

  async send(payload: NotificationPayload): Promise<void> {
    const headers: Record<string, string> = {
      "Content-Type": "application/json",
      "User-Agent": "SatoPi-Swarm/1.0",
    };
    if (this.options.secret) {
      headers["Authorization"] = \`Bearer \${this.options.secret}\`;
    }

    const controller = new AbortController();
    const timeout = setTimeout(
      () => controller.abort(),
      this.options.timeout ?? 10_000,
    );

    const response = await fetch(this.url, {
      method: "POST",
      headers,
      body: JSON.stringify(payload),
      signal: controller.signal,
    });

    clearTimeout(timeout);

    if (!response.ok) {
      throw new Error(
        \`Webhook \${this.url} returned \${response.status}: \${await response.text()}\`,
      );
    }
  }
}

// ============================================================================
// Router
// ============================================================================

/** Dispatches a notification to every configured channel concurrently. */
async function notifyAll(
  channels: NotificationChannel[],
  payload: NotificationPayload,
): Promise<ChannelResult[]> {
  const results = await Promise.allSettled(
    channels.map(async (ch): Promise<ChannelResult> => {
      const start = performance.now();
      await ch.send(payload);
      return {
        channel: ch.name,
        success: true,
        durationMs: Math.round(performance.now() - start),
      };
    }),
  );

  return results.map((r, i) =>
    r.status === "fulfilled"
      ? r.value
      : {
          channel: channels[i]!.name,
          success: false,
          error: (r.reason as Error).message,
          durationMs: 0,
        },
  );
}

// ============================================================================
// Helpers
// ============================================================================

function buildMarkdown(payload: NotificationPayload): string {
  const lines: string[] = [];
  lines.push(\`# Swarm Pipeline: \${payload.name}\`);
  lines.push("");
  lines.push(\`- **Status**: \${payload.status}\`);
  lines.push(\`- **Mode**: \${payload.mode}\`);
  lines.push(\`- **Iterations**: \${payload.iterations}\`);
  lines.push(\`- **Timestamp**: \${payload.timestamp}\`);
  lines.push("");

  lines.push("## Agent Results");
  lines.push("");
  for (const [name, agent] of Object.entries(payload.agents)) {
    lines.push(\`- **\${name}**: \${agent.status} (\${agent.duration})\`);
  }

  if (payload.errors.length > 0) {
    lines.push("");
    lines.push("## Errors");
    lines.push("");
    for (const error of payload.errors) {
      lines.push(\`- \${error}\`);
    }
  }

  return lines.join("\\n") + "\\n";
}

// ============================================================================
// Demo
// ============================================================================

async function main(): Promise<void> {
  const payload: NotificationPayload = {
    name: "loop-engineering",
    mode: "loop",
    status: "completed",
    iterations: 1,
    agents: {
      lancelot: { status: "completed", duration: "12.3s" },
      bors: { status: "completed", duration: "8.1s" },
      dinadan: { status: "completed", duration: "2.4s" },
    },
    errors: [],
    timestamp: new Date().toISOString(),
  };

  const channels: NotificationChannel[] = [
    new FileChannel("/tmp/swarm-notification.md"),
    // Replace with a real webhook URL to test (webhook.site, etc.)
    new WebhookChannel("https://httpbin.org/post", { timeout: 5000 }),
  ];

  console.log("Dispatching notification to %d channels...", channels.length);
  console.log("Payload:", JSON.stringify(payload, null, 2));
  console.log("");

  const results = await notifyAll(channels, payload);

  console.log("Results:");
  for (const r of results) {
    const icon = r.success ? "✓" : "✗";
    console.log(\`  \${icon} \${r.channel} (\${r.durationMs}ms)\`);
    if (r.error) {
      console.log(\`    Error: \${r.error}\`);
    }
  }

  // Verify file channel wrote correctly
  const fileContent = await Bun.file("/tmp/swarm-notification.md").text();
  console.log("\\n--- File output preview ---");
  console.log(fileContent.slice(0, 300));
}

main().catch(console.error);
\`\`\`

---

## Design Notes

| Decision | Rationale |
|---|---|
| **\`NotificationChannel\` interface** | Single \`send(payload)\` method — minimal contract, easy to implement new channels (Slack, email, Discord). |
| **Concurrent dispatch via \`Promise.allSettled\`** | One slow/hanging channel never blocks others. Results collected regardless of individual failures. |
| **File channel uses \`Bun.write\`** | Consistent with SatoPi conventions (Bun-native I/O). \`Bun.write\` auto-creates parent directories. |
| **Webhook channel: fetch + AbortController** | Built-in Bun API. Timeout defaults to 10s. Authorization header via \`secret\` option. |
| **AbortController timeout** | Prevents webhook hangs from blocking pipeline teardown. Kay's performance concern already addressed. |
| **\`notifyAll\` returns structured results** | Pipeline can log/report which channels failed without crashing. |

## Integration Point

Where this hooks into the pipeline (see \`extension.ts:handleRun\`):

\`\`\`typescript
