function buildMarkdown(payload: NotificationPayload): string {
  const lines: string[] = [];
  lines.push(`# Swarm Pipeline: ${payload.name}`);
  lines.push("");
  lines.push(`- **Status**: ${payload.status}`);
  lines.push(`- **Mode**: ${payload.mode}`);
  lines.push(`- **Iterations**: ${payload.iterations}`);
  lines.push(`- **Timestamp**: ${payload.timestamp}`);
  lines.push("");

  lines.push("## Agent Results");
  lines.push("");
  for (const [name, agent] of Object.entries(payload.agents)) {
    lines.push(`- **${name}**: ${agent.status} (${agent.duration})`);
  }

  if (payload.errors.length > 0) {
    lines.push("");
    lines.push("## Errors");
    lines.push("");
    for (const error of payload.errors) {
      lines.push(`- ${error}`);
    }
  }

  return lines.join("\n") + "\n";
}

